import{_ as t,o as r,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Volume Credits (INTERNAL)","description":"","frontmatter":{"title":"Volume Credits (INTERNAL)","slug":"volume-credits-internal"},"headers":[],"relativePath":"marketer-hub/volume-credits-internal.md","filePath":"marketer-hub/volume-credits-internal.md"}'),o={name:"marketer-hub/volume-credits-internal.md"};function s(i,e,l,c,h,d){return r(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch uses the concept of <strong>volume credits</strong> for billing.</p><p>Volume credits correspond to the number of end-user actions tracked, attributed, or reported on in Branch.</p><p>At the core of end-user actions are <strong>Branch Events</strong>.</p><h2 id="branch-events-explained" tabindex="-1">Branch Events Explained <a class="header-anchor" href="#branch-events-explained" aria-label="Permalink to &quot;Branch Events Explained&quot;">​</a></h2><p>First of all, what is a Branch Event?</p><p>Branch Events are user actions that Branch tracks automatically through our SDK, as well as additional user actions you choose to send to Branch for tracking or reporting purposes.</p><p>Logging Branch Events helps you see how a user moves through your app and what actions they are taking along the way.</p><p>Examples of some commonly used Branch Events include: Clicks, Impressions, Installs, Purchases, Shares, and Logins. All of these are examples of Branch Events that have properties that are pre-defined by Branch.</p><p>If you want to create an event with your own properties, you can create a Branch <strong>Custom</strong> Event.</p><p>In terms of pre-defined Branch Events, there are three categories: Commerce, Content, and User Lifecycle. You&#39;ll learn more about these categories in this guide.</p><h2 id="branch-events-and-volume-credits" tabindex="-1">Branch Events and Volume Credits <a class="header-anchor" href="#branch-events-and-volume-credits" aria-label="Permalink to &quot;Branch Events and Volume Credits&quot;">​</a></h2><p>For billing purposes, an event can fall into one of the following buckets:</p><ul><li>Events that <em>never count</em> toward your volume credit limit.</li><li>Events that count toward your volume credit limit <strong>only</strong> if they are driven by Branch Links.</li><li>Events that <em>always count</em> toward your volume credit limit.</li></ul><p>Let&#39;s consider the buckets in turn and what types of Branch Events live in each.</p><h3 id="never-count" tabindex="-1">Never Count <a class="header-anchor" href="#never-count" aria-label="Permalink to &quot;Never Count&quot;">​</a></h3><p>Some Branch Events don&#39;t count toward your volume credit limit and are simply included. These are:</p><ul><li><strong>Impressions</strong>: When paid ads are rendered on a user&#39;s screen.</li><li><strong>Clicks</strong>: Whenever a Branch Link is clicked.</li><li><strong>Web Page Views</strong>: Measured every time a webpage loads with the Branch Web SDK.</li><li><strong>Web Session Starts</strong>: When a webpage with the Branch Web SDK opens in a new tab, or when a user clicks on a Branch Link and is redirected to a page with the Branch Web SDK.</li></ul><p>Note that both of these events are automatically tracked by your Branch SDK integration.</p><h3 id="count-when-driven-by-branch" tabindex="-1">Count When Driven By Branch <a class="header-anchor" href="#count-when-driven-by-branch" aria-label="Permalink to &quot;Count When Driven By Branch&quot;">​</a></h3><p>There are other Branch Events that are also automatically tracked by your Branch SDK integration, but they <strong>will</strong> count toward your volume credit limit if they were tracked, driven by, and reported on in Branch.</p><p>These are:</p><ul><li><strong>Opens</strong>: Occur every time an app is opened on a device (after the initial Install).</li><li><strong>Installs</strong>: Measured by Branch the first time the app is opened on a device.</li><li><strong>Reinstalls</strong>: The first time a user installs an app after previously uninstalling it.</li></ul><p>If these were driven by a Branch Link, then they will count toward your volume credits. In this way, Branch&#39;s pricing is closely tied to the growth of your product and the value Branch brings to your brand.</p><h3 id="always-count" tabindex="-1">Always Count <a class="header-anchor" href="#always-count" aria-label="Permalink to &quot;Always Count&quot;">​</a></h3><p>Lastly, there are Branch Events that always count toward your volume credit limit.</p><p>Events in this category are considered <strong>conversion events</strong>. These are not automatically tracked by the Branch SDK by default.</p><p>These are:</p><ul><li><p><strong>Commerce Events</strong>: Includes purchases and transactions, as well as actions related to carts and wishlists.</p><ul><li>Examples: Branch customers frequently use Commerce Events to track how many times an item is added to a cart or wishlist, if a purchase is initiated, and if an end user adds payment info.</li></ul></li><li><p><strong>Content Events</strong>: Occur when a user engages with your in-app content.</p><ul><li>Examples: When posting in-app articles, a Branch customer may use this to track events related to users performing search queries, viewing content, rating the content, or sharing it.</li></ul></li><li><p><strong>User Lifecycle Events</strong>: Actions the user takes in your app to continue progressing through it.</p><ul><li>Examples: Can be used to track users completing a tutorial, opting in to an email list, or starting a free trial.</li></ul></li><li><p><strong>Custom Events</strong>: Actions you want to track that Branch has no corresponding pre-defined event for.</p></li></ul><p>Within the Commerce, Content, and User Lifecycle categories, there exists a set of events to choose from. You can learn more about those specific events in our event tracking <a href="./track-branch-events.html#event-tracking">guide</a>.</p><p>All of these, or any type of Custom Branch Event you create with your own properties, will count against your volume credit limit.</p><h2 id="events-volume-credits-table" tabindex="-1">Events + Volume Credits Table <a class="header-anchor" href="#events-volume-credits-table" aria-label="Permalink to &quot;Events + Volume Credits Table&quot;">​</a></h2><p>View the table below to quickly see which Branch Events fall into which bucket, as well as whether that event type is automatically tracked by our SDKs.</p><table tabindex="0"><thead><tr><th>Event Type</th><th>Tracked Automatically by SDK?</th><th>Counts Toward Volume Credit Limit?</th></tr></thead><tbody><tr><td>Impression</td><td>Yes</td><td>No</td></tr><tr><td>Click</td><td>Yes</td><td>No</td></tr><tr><td>Webhook</td><td>No</td><td>No</td></tr><tr><td>Open</td><td>Yes</td><td><strong>Only</strong> if attributed to Branch</td></tr><tr><td>Web Session Start</td><td>Yes (Web SDK)</td><td><strong>Only</strong> if attributed to Branch</td></tr><tr><td>Install</td><td>Yes</td><td><strong>Only</strong> if attributed to Branch</td></tr><tr><td>Reinstall</td><td>Yes</td><td><strong>Only</strong> if attributed to Branch</td></tr><tr><td><a href="./track-branch-events.html#track-commerce-events">Commerce</a></td><td>No</td><td>Yes</td></tr><tr><td><a href="./track-branch-events.html#track-content-events">Content</a></td><td>No</td><td>Yes</td></tr><tr><td><a href="./track-branch-events.html#track-lifecycle-events">User LifecycleLifecycle</a></td><td>No</td><td>Yes</td></tr><tr><td><a href="./track-branch-events.html#track-custom-events">Custom</a></td><td>No</td><td>Yes</td></tr></tbody></table><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>To make sure your events are being sent to Branch from your app, you can check the Liveview <a href="https://dashboard.branch.io/liveview/events" target="_blank" rel="noreferrer">page</a> of the Branch Dashboard.</p><p>Please note that it may take several minutes for your events to appear in Liveview after they&#39;ve been triggered.</p>',37)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
